//
//  DeviceListViewModel.swift
//  Radiacode
//
//  Created by Matvey Kozin on 20.05.2024.
//

import Foundation
import Combine
import FactoryKit

@Observable
final class DeviceListViewModel {

    enum ViewType {
        case `default`
        case noDevices
        case bluetoothDisabled
        case bluetoothNotAuthorized
    }

    @ObservationIgnored
    @Injected(\.deviceFoundManager) private var deviceFoundManager
    @ObservationIgnored
    @Injected(\.deviceConnectionManager) private var deviceConnectionManager
    @ObservationIgnored
    @Injected(\.bluetoothManager) private var bluetoothManager

    var isSearching: Bool = false
    var devices: [RadiaCode] = []
    var viewType: ViewType = .default

    @ObservationIgnored
    private var cancellable: Set<AnyCancellable> = .init()

    func fetch(currentDeviceIdentifier: String?) {
        deviceFoundManager.startSearching()

        deviceFoundManager.observeSearchingState
            .receive(on: DispatchQueue.main)
            .assign(to: \.isSearching, on: self)
            .store(in: &cancellable)

        deviceFoundManager.foundDeviceObserver
            .receive(on: DispatchQueue.main)
            .sink(receiveCompletion: { _ in }, receiveValue: { [weak self] radiacode in
                guard let self = self,
                      radiacode.device.identifier != currentDeviceIdentifier,
                      !self.devices.contains(radiacode) else {
                    return
                }
                self.devices.append(radiacode)
            })
            .store(in: &cancellable)

        bluetoothManager.bluetoothStatus
            .receive(on: DispatchQueue.main)
            .sink { [weak self] status in
                guard let self else { return }
                switch status {
                case .notAuthorized:
                    viewType = .bluetoothNotAuthorized
                case .poweredOn, .unknown:
                    viewType = .default
                case .poweredOff:
                    viewType = .bluetoothDisabled
                }
            }
            .store(in: &cancellable)

        if currentDeviceIdentifier == nil {
            startNotFoundCheck()
        }
    }

    func connect(radiacode: RadiaCode) {
        Task {
            await deviceConnectionManager.connect(radiacode: radiacode)
        }
    }

    func startNotFoundCheck() {
        viewType = .default
        Task {
            try? await Task.sleep(seconds: 30)
            if self.devices.isEmpty {
                await MainActor.run {
                    viewType = .noDevices
                }
            }
        }
    }

    deinit {
        deviceFoundManager.stopSearching()
    }
}

