//
//  BluetoothStrenght.swift
//  Radiacode
//
//  Created by Matvey Kozin on 12.10.2023.
//

import Foundation

enum BluetoothSignal {

    case strong
    case good
    case fair
    case poor
    case noSignal

    var value: Double {
        switch self {
        case .strong: 1.0
        case .good: 0.75
        case .fair: 0.5
        case .poor: 0.25
        case .noSignal: 0
        }
    }

    init(doubleValue: Double) {
        if doubleValue >= -60 {
            self = .strong
        } else if doubleValue < -60 && doubleValue >= -70 {
            self = .good
        } else if doubleValue < -70 && doubleValue >= -80 {
            self = .fair
        } else if doubleValue < -80 && doubleValue >= -90 {
            self = .poor
        } else {
            self = .noSignal
        }
    }
}

content.text:
Да, это легко реализуемо. Вот предлагаемый подход:

**Идея:** устройства в первую секунду буферизуем, после — сортируем по `signal.value` (ближе = выше), затем новые просто дописываем в конец.

Изменения только в [`DeviceListViewModel.swift`](RadiaCode/Presentation/Containers/ControlCenter/DeviceList/DeviceListViewModel.swift):

```swift
// Добавить два поля
@ObservationIgnored
private var initialSortDone: Bool = false

@ObservationIgnored
private var pendingDevices: [RadiaCode] = []
```

В `fetch()` заменить блок `foundDeviceObserver` и добавить Task:

```swift
deviceFoundManager.foundDeviceObserver
    .receive(on: DispatchQueue.main)
    .sink(receiveCompletion: { _ in }, receiveValue: { [weak self] radiacode in
        guard let self = self,
              radiacode.device.identifier != currentDeviceIdentifier else { return }

        if self.initialSortDone {
            guard !self.devices.contains(radiacode) else { return }
            self.devices.append(radiacode)
        } else {
            guard !self.pendingDevices.contains(radiacode) else { return }
            self.pendingDevices.append(radiacode)
        }
    })
    .store(in: &cancellable)

Task {
    try? await Task.sleep(seconds: 1)
    await MainActor.run {
        self.devices = self.pendingDevices.sorted { $0.signal.value > $1.signal.value }
        self.initialSortDone = true
        self.pendingDevices = []
    }
}
```

**Как работает:**
- Первая секунда: устройства идут в `pendingDevices`, список пустой (пользователь видит поиск)
- Через 1 сек: `devices` выставляется отсортированным по `signal.value` (1.0 → 0.0, т.е. ближе — выше)
- Далее: новые устройства просто `append` без пересортировки

**Нюанс:** первую секунду список будет пустой, хотя уже есть найденные устройства — это ок, т.к. они все равно покажутся сразу после сортировки. Если хочешь, чтобы в первую секунду тоже что-то отображалось, могу добавить промежуточный вывод.

Применить?

