//
//  DeviceListView.swift
//  Radiacode
//
//  Created by Matvey Kozin on 23.03.2023.
//

import SwiftUI
import FactoryKit

struct DeviceListView: View {

    @InjectedObservable(\.deviceContainer) private var deviceContainer
    @Injected(\.analyticsEngine) private var analyticsEngine

    @LazyState private var viewModel = DeviceListViewModel()
    @Binding var showDeviceList: Bool

    var body: some View {
        NavigationStack {
            VStack {
                switch viewModel.viewType {
                case .noDevices:
                    DeviceErrorView(
                        state: .search,
                        title: .ControlCenter.deviceNotFound,
                        message: .ControlCenter.makeSureYourRadiacodeDeviceIsOnAndNotConnectedToAnotherDevice,
                        button: (.ControlCenter.tryAgain, {
                            viewModel.startNotFoundCheck()
                        })
                    )
                case .bluetoothDisabled:
                    DeviceErrorView(
                        state: .bluetooth,
                        title: .ControlCenter.bluetoothTurnedOff,
                        message: .ControlCenter.toConnectYourRadiacodeTurnOnBluetooth,
                        button: nil
                    )
                case .bluetoothNotAuthorized:
                    DeviceErrorView(
                        state: .bluetooth,
                        title: .ControlCenter.bluetoothAccessIsDenied,
                        message: .ControlCenter.toConnectRadiacodeAllowTheAppToUseBluetoothInSettings,
                        button: (.Base.openSettings, {
                            if let url = URL(string: UIApplication.openSettingsURLString) {
                                UIApplication.shared.open(url)
                            }
                        })
                    )
                case .default:
                    List {
                        HStack {
                            Text(.ControlCenter.selectDeviceFromList)
                                .font(.system(size: 17))
                                .foregroundStyle(.textSecondary)
                            Spacer()
                        }
                        .listRowBackground(Color.clear)
                        .listRowSeparator(.hidden)

                        if let currentDevice = deviceContainer.current {
                            ConnectionDeviceView(bluetoothDevice: currentDevice)
                                .padding(.horizontal, 20)
                                .padding(.vertical, 12)
                                .roundedBackground()
                                .onTapGesture {
                                    analyticsEngine.reportEvent(DeviceListAnalyticsEvent.alreadySelectedDeviceClick)
                                    showDeviceList.toggle()
                                }
                                .listRowBackground(Color.clear)
                                .listRowSeparator(.hidden)
                                .listRowInsets(EdgeInsets(top: 6, leading: 16, bottom: 6, trailing: 16))
                        }

                        ForEach(viewModel.devices, id: \.device.identifier) { device in
                            deviceRow(device)
                                .listRowBackground(Color.clear)
                                .listRowSeparator(.hidden)
                                .listRowInsets(EdgeInsets(top: 6, leading: 16, bottom: 6, trailing: 16))
                        }

                        if viewModel.isSearching {
                            VStack {
                                LoaderTextView(title: .ControlCenter.searching)
                            }
                            .listRowBackground(Color.clear)
                            .listRowSeparator(.hidden)
                        }
                    }
                    .scrollIndicators(.hidden)
                    .scrollContentBackground(.hidden)
                    .listStyle(.plain)
                    .safeAreaInset(edge: .bottom, spacing: 0) {
                        Spacer()
                            .frame(height: 40)
                    }
                }
            }
            .background(.dark06)
            .toolbar {
                CloseButton {
                    analyticsEngine.reportEvent(DeviceListAnalyticsEvent.closeClick)
                    showDeviceList = false
                }
            }
            .ignoresSafeArea(.all, edges: .bottom)
            .navigationTitle(.ControlCenter.devices)
            .navigationBarTitleDisplayMode(.automatic)
            .scrollBounceBehavior(.basedOnSize, axes: .vertical)
        }
        .onAppear {
            analyticsEngine.reportEvent(DeviceListAnalyticsEvent.mainScreenShow)
        }
        .task {
            viewModel.fetch(currentDeviceIdentifier: deviceContainer.current?.identifier)
        }
    }

    private func deviceRow(_ radiacode: RadiaCode) -> some View {
        DeviceView(
            device: radiacode.device,
            signal: radiacode.signal
        )
        .frame(maxWidth: .infinity, alignment: .leading)
        .padding(.horizontal, 20)
        .padding(.vertical, 12)
        .roundedBackground()
        .onTapGesture {
            analyticsEngine.reportEvent(DeviceListAnalyticsEvent.deviceSelectClick(radiacode.device))
            viewModel.connect(radiacode: radiacode)
            UIApplication.rootViewController?.dismiss(animated: true)
        }
    }
}

#Preview {
    DeviceListView(showDeviceList: .constant(false))
}

