//
//  RadiaCodeDevice.swift
//  Radiacode
//
//  Created by Matvey Kozin on 19.09.2023.
//

import Foundation
import CoreBluetooth

/// Найденное устройство для подключения
struct RadiaCode: Equatable {

    static let hostID: UInt32 = 0xFF12FF01

    let device: Device
    let signal: BluetoothSignal
    let connection: CBPeripheral

    static func == (lhs: RadiaCode, rhs: RadiaCode) -> Bool {
        lhs.device == rhs.device
    }
}

extension RadiaCode {

    struct Device: Hashable {

        let identifier: String
        let model: Model

        init(identifier: String, model: String) {
            self.identifier = identifier
            self.model = Model(rawValue: model)
        }

        init?(serialNumber: String) {
            let parts = serialNumber.split(separator: "-", omittingEmptySubsequences: false).map(String.init)
            guard parts.count >= 3, parts[0] == "RC" else { return nil }
            self.identifier = serialNumber
            self.model = Model(serialCode: parts[1])
        }

        static func == (lhs: Device, rhs: Device) -> Bool {
            lhs.identifier == rhs.identifier
        }
    }
}

extension RadiaCode {

    enum Family {
        case radiaCode10x
        case radiaCode11x
        case radiaCode103G
        case radiaCode41x

        var postFix: String {
            switch self {
            case .radiaCode10x: return "_10x"
            case .radiaCode11x: return "_11x"
            case .radiaCode103G: return "_103G"
            case .radiaCode41x: return "_41x"
            }
        }
    }

    /// Модели устройств RadiaCode
    enum Model: Hashable {

        static let defaultName = "RadiaCode"

        case radiacode101
        case radiacode102
        case radiacode103
        case radiacode103G
        case radiacode110
        case radiacodeZero
        case radiacode(String)

        typealias RawValue = String

        init(rawValue: String) {
            switch rawValue {
            case "RadiaCode-101": self = .radiacode101
            case "RadiaCode-102": self = .radiacode102
            case "RadiaCode-103": self = .radiacode103
            case "RadiaCode-103G": self = .radiacode103G
            case "RadiaCode-110": self = .radiacode110
            case "RadiaCode Zero": self = .radiacodeZero
            default: self = .radiacode(rawValue)
            }
        }

        init(serialCode: String) {
            switch serialCode {
            case "101": self = .radiacode101
            case "102": self = .radiacode102
            case "103": self = .radiacode103
            case "103G": self = .radiacode103G
            case "110": self = .radiacode110
            case "Zero", "410": self = .radiacodeZero
            default: self = .radiacode("RadiaCode-\(serialCode)")
            }
        }

        var family: Family {
            switch self {
            case .radiacode101, .radiacode102, .radiacode103:
                return .radiaCode10x
            case .radiacode103G:
                return .radiaCode103G
            case .radiacode110:
                return .radiaCode11x
            case .radiacodeZero:
                return .radiaCode41x
            case .radiacode(let name):
                if name.hasPrefix("RadiaCode-10") {
                    return .radiaCode10x
                } else if name.hasPrefix("RadiaCode-11") {
                    return .radiaCode11x
                } else if name.hasPrefix("RadiaCode-41") {
                    return .radiaCode41x
                } else {
                    return .radiaCode10x
                }
            }
        }

        var name: String {
            switch self {
            case .radiacode101: "RadiaCode-101"
            case .radiacode102: "RadiaCode-102"
            case .radiacode103: "RadiaCode-103"
            case .radiacode103G: "RadiaCode-103G"
            case .radiacode110: "RadiaCode-110"
            case .radiacodeZero: "RadiaCode-Zero"
            case .radiacode(let name): name
            }
        }
    }
}

