//
//  DeviceFoundManager.swift
//  Radiacode
//
//  Created by Matvey Kozin on 13.09.2023.
//

import Foundation
import Combine
import FactoryKit

/// Менеджер поиска устройств для подключения
protocol DeviceFoundManager {

    /// Observer найденного устройсива
    var foundDeviceObserver: PassthroughSubject<RadiaCode, Error> { get }

    /// Observer состояния поиска
    var observeSearchingState: AnyPublisher<Bool, Never> { get }

    /// Запускает поиск устройств
    func startSearching()

    /// Останавливает поиск устройств
    func stopSearching()
}

/// Реализация менеджера поиска устройств для подключения
final class DeviceFoundManagerImpl: DeviceFoundManager {

    @Injected(\.bluetoothManager) private var bluetoothManager

    var foundDeviceObserver: PassthroughSubject<RadiaCode, Error> = .init()

    var observeSearchingState: AnyPublisher<Bool, Never> {
        bluetoothManager.observeScanningStatus
    }

    private var searchCounter = Counter()
    private var isSearching = false

    private var managerCancellables: Set<AnyCancellable> = .init()

    init() {
        setupObservers()
    }

    func startSearching() {
        Task {
            await searchCounter.increment()
            if !isSearching {
                isSearching = true
                bluetoothManager.startScan()
            }
        }
    }

    func stopSearching() {
        Task {
            await searchCounter.decrement()
            if await searchCounter.value == 0 {
                isSearching = false
                bluetoothManager.stopScan()
            } 
        }
    }

    private func setupObservers() {
        bluetoothManager.observeDevice
            .sink { foundDevice in
                self.foundDeviceObserver.send(foundDevice)
            }.store(in: &managerCancellables)
    }
}

        bleStatusObserver.send(true)
        bluetoothStatus.send(.poweredOn)
    @unknown default:
        bluetoothStatus.send(.unknown)
    }
}

func centralManager(
    _ central: CBCentralManager,
    didDiscover peripheral: CBPeripheral,
    advertisementData: [String: Any],
    rssi RSSI: NSNumber
) {
    let localName = DeviceBluetoothConstants.PeripheralAdvertisementKeys.localName.rawValue

    guard let name = peripheral.name, let localName = advertisementData[localName] as? String else {
        return
    }

    let peripheralName = name.contains(RadiaCode.Model.defaultName) ? name : localName

    guard peripheralName.hasPrefix(RadiaCode.Model.defaultName) else {
        return
    }

    let splittedName = peripheralName.components(separatedBy: "#")

    let deviceId: String
    let deviceName: String

    if splittedName.count == 2 {
        deviceId = splittedName[1]
        deviceName = splittedName[0]
    } else {
        deviceId = peripheral.identifier.uuidString
        deviceName = RadiaCode.Model.defaultName
    }

    let foundDevice = RadiaCode(
        device: .init(identifier: deviceId, model: deviceName),
        signal: .init(doubleValue: RSSI.doubleValue),
        connection: peripheral
    )
    devicesObserver.send(foundDevice)
}

func centralManager(_ central: CBCentralManager, didConnect peripheral: CBPeripheral) {
    peripheral.discoverServices([Consts.radiaCodeServiceCBUUID])
    peripheral.readRSSI()
}

content.text:
Это потому что разные устройства имеют разные интервалы advertising (от 100мс до 1280мс). Близкое может «опоздать» — его батч прилетел позже, а мы тогда просто `append` в конец.

Решение — вставлять новые устройства в правильную позицию по сигналу, не пересортировывая весь список:

```swift
deviceFoundManager.foundDeviceObserver
    .filter { $0.device.identifier != currentDeviceIdentifier }
    .collect(.byTime(DispatchQueue.main, .seconds(0.2)))
    .map { Set<RadiaCode>($0) }
    .receive(on: DispatchQueue.main)
    .sink(receiveCompletion: { _ in }, receiveValue: { [weak self] batch in
        guard let self else { return }
        for device in batch where !self.devices.contains(device) {
            let index = self.devices.firstIndex { $0.signal.value < device.signal.value }
                ?? self.devices.endIndex
            self.devices.insert(device, at: index)
        }
    })
    .store(in: &cancellable)
```

`Set` дедуплицирует внутри батча, `firstIndex { < }` находит позицию для вставки в уже отсортированный список. Если устройство сильнее всех — вставится в начало, слабее всех — в конец. Существующие позиции не меняются, только сдвигаются.

