import Foundation

/// Пороговые значения тревог
@Observable
final class Alarm: Equatable, Codable {

    enum Consts {
        static let initialMaxCountRate: Float = 30.0
        static let initialMaxDoseRate: Float = 0.7
    }

    /// Уровни тревог
    struct Level: Equatable, Codable {

        let radiationType: RadiationType
        /// Первый порог
        var level1: Decimal?
        /// Второй порог
        var level2: Decimal?
        /// Зашкал
        var offScale: Decimal?

        /// Проверка значения на Алерт
        /// - Parameter value: значение
        /// - Returns: алерт
        func checkValue(_ value: Float) -> SignalizationAlarmLevel {
            if let offScale = offScale?.floatValue, value >= offScale {
                return .offScale
            }
            if let level2 = level2?.floatValue, value >= level2 {
                return .level2
            }
            if let level1 = level1?.floatValue, value >= level1 {
                return .level1
            }
            return .normal
        }

        var isEmpty: Bool {
            level1 == nil && level2 == nil
        }
    }

    /// Пороги по скорости счета [имп. за 10 с]
    var countRate: Level
    /// Пороги по мощности дозы
    var doseRate: Level
    /// Пороги по дозе
    var dose: Level

    var isEmpty: Bool {
        countRate.isEmpty && doseRate.isEmpty && dose.isEmpty
    }

    init(
        countRate: Level = Level(radiationType: .radiationLevel(.countRate)),
        doseRate: Level = Level(radiationType: .radiationLevel(.doseRate)),
        dose: Level = Level(radiationType: .dose)
    ) {
        self.countRate = countRate
        self.doseRate = doseRate
        self.dose = dose
    }

    enum CodingKeys: String, CodingKey {
        case countRate
        case doseRate
        case dose
    }

    required init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        self.countRate = try container.decode(Level.self, forKey: .countRate)
        self.doseRate = try container.decode(Level.self, forKey: .doseRate)
        self.dose = try container.decode(Level.self, forKey: .dose)
    }

    func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        try container.encode(countRate, forKey: .countRate)
        try container.encode(doseRate, forKey: .doseRate)
        try container.encode(dose, forKey: .dose)
    }

    static func == (lhs: Alarm, rhs: Alarm) -> Bool {
        lhs.countRate == rhs.countRate &&
        lhs.doseRate == rhs.doseRate &&
        lhs.dose == rhs.dose
    }
}

extension Alarm.Level {

    /// Преобразование значения регистра устройства во внутреннее значение приложения.
    /// Формулы — Protocol.pdf, разделы "Пороги по скорости счёта" / "Пороги по дозе" / "Пороги по мощности дозы".
    static func decode(rawValue: UInt32, for type: RadiationType, doseAlarmMultiplier: UInt32) -> Decimal {
        switch type {
        case .radiationLevel(.countRate):
            Decimal(rawValue) / 10
        case .radiationLevel(.doseRate):
            Decimal(rawValue) / 100
        case .dose:
            // Protocol.pdf, "Пороги по дозе": val_μR = register × DS_AlarmVsfrMul
            Decimal(rawValue) * Decimal(doseAlarmMultiplier)
        }
    }

    /// Преобразование внутреннего значения приложения в значение регистра устройства.
    static func encode(value: Decimal, for type: RadiationType, doseAlarmMultiplier: UInt32) -> UInt32 {
        switch type {
        case .radiationLevel(.countRate):
            UInt32(value.floatValue * 10)
        case .radiationLevel(.doseRate):
            UInt32(value.floatValue * 100)
        case .dose:
            // Protocol.pdf, "Пороги по дозе": uint32(val / DS_AlarmVsfrMul + 0.01), float64
            UInt32(value.doubleValue / Double(doseAlarmMultiplier) + 0.01)
        }
    }
}

