//
//  Array+Data.swift
//  Radiacode
//
//  Created by Pavel Marinchenko on 29.05.2023.
//

import Foundation

extension Array where Array.Element == UInt8 {

    func toBinaryInteger<T: FixedWidthInteger>(start: Int) -> T {
        var collectedBytes: [Element] = []

        let length = T.bitWidth / 8

        for index in start..<start + length where index < count {
            collectedBytes.append(self[index])
        }

        return collectedBytes.withUnsafeBytes { pointer in
            UnsafeRawPointer(pointer.baseAddress!).load(as: T.self)
        }
    }

    func toFloat(start: Int) -> Float32 {
        var bytes: [UInt8] = []
        let floatSize = 4

        for index in start..<start + floatSize where index < count {
            bytes.append(self[index])
        }
        var floatValue: Float32 = 0.0
        memcpy(&floatValue, bytes, floatSize)

        return floatValue
    }
}

extension Array {
    func chunks(by size: Int) -> [[Element]] {
        stride(from: 0, to: count, by: size).map {
            Array(self[$0 ..< Swift.min($0 + size, count)])
        }
    }
}

extension String {
    func components(withLength length: Int) -> [String] {
        stride(from: 0, to: count, by: length).map {
            let start = index(startIndex, offsetBy: $0)
            let end = index(start, offsetBy: length, limitedBy: endIndex) ?? endIndex
            return String(self[start..<end])
        }
    }
}

extension Array where Element: Hashable {
    func difference(from other: [Element]) -> [Element] {
        let thisSet = Set(self)
        let otherSet = Set(other)
        return Array(thisSet.symmetricDifference(otherSet))
    }
}

extension Array where Element: Equatable {
    subscript(safe bounds: Range<Int>) -> ArraySlice<Element> {
        if bounds.lowerBound > count { return [] }
        let lower = Swift.max(0, bounds.lowerBound)
        let upper = Swift.max(0, Swift.min(count, bounds.upperBound))
        return self[lower..<upper]
    }
}

extension Array where Element: Comparable {
    mutating func insertSorted(_ newElement: Element) {
        if isEmpty {
            append(newElement)
            return
        }

        if let last, last < newElement {
            append(newElement)
            return
        }

        var low = 0
        var high = count - 1

        while low <= high {
            let mid = low + (high - low) / 2
            if self[mid] == newElement {
                self.insert(newElement, at: mid)
                return
            } else if self[mid] < newElement {
                low = mid + 1
            } else {
                high = mid - 1
            }
        }
        insert(newElement, at: low)
    }
}

extension Array where Element: Numeric {
    func trimArray() -> [Element] {
        var trimmedArray = self
        while trimmedArray.last == 0 {
            trimmedArray.removeLast()
        }
        return trimmedArray
    }

    func fillZeroArray(count: Int) -> [Element] {
        self + Array(repeating: 0, count: Swift.max(0, count - self.count))
    }
}

extension Array: @retroactive Identifiable where Element: Hashable {
   public var id: Self { self }
}

extension Numeric {

    var asBytes: [UInt8] {
        withUnsafeBytes(of: self) { Array($0) }
    }
}

