import Foundation

/// Запрашивает настройки устройства
struct SettingsCommand: BluetoothCommand {

    enum Action {
        case read
        case write
    }

    let request: BluetoothCommandRequest

    init(setting: BluetoothCommandOperation, action: Action = .read, payload: UInt32? = nil) {
        self.request = .init(
            type: action == .read ? .readVirtualSFR : .writeVirtualSFR,
            command: setting,
            payload: payload?.asBytes ?? nil
        )
    }
}

// MARK: - Response

extension SettingsCommand {

    struct Response {
        let register: UInt32
        let value: UInt32
    }

    var response: BluetoothCommandResponseBuilder<Response> {
        .init { storage in
            return .init(register: request.command.rawValue, value: storage.body.toBinaryInteger(start: 0))
        }
    }
}

