import Foundation

extension BluetoothDevice {

    struct ConfigurationSettings: Sendable {
        /// Используется ли сжатый формат спектра
        let specFormatVersion: Bool
        /// Наличие или отсутствие режима спектра
        let disableSpectrum: Bool
        /// Наличие или отсутствие режима жесткости
        let disableHardness: Bool
