//
//  DataBufferCommand.Model.swift
//  Radiacode
//
//  Created by Matvey Kozin on 27.09.2023.
//

import Foundation

typealias FirmwareFeatureLevel = DataBufferCommand.Response.FrameHeader.FrameVersion

extension DataBufferCommand.Response.FrameHeader {

    enum FrameVersion: String, CaseIterable, Comparable {
        case v4_07
        case v4_08
        case v4_11
        case v4_13

        var supportAveragingRawData: Bool {
            self >= .v4_08
        }

        var supportDoseCounter: Bool {
            self >= .v4_13
        }

        private var sortOrder: Int {
            switch self {
            case .v4_07: 1
            case .v4_08: 2
            case .v4_11: 3
            case .v4_13: 4
            }
        }

        static func < (lhs: DataBufferCommand.Response.FrameHeader.FrameVersion, rhs: DataBufferCommand.Response.FrameHeader.FrameVersion) -> Bool {
            lhs.sortOrder < rhs.sortOrder
        }
    }

    /*--- RC_GroupId ---*/
    enum GroupId: String {
        // MARK: - Deprecated in V4.08+
        case countRate = "GRP_CountRate"
        case doseRate = "GRP_DoseRate"
        case rawCountRate = "GRP_RawCountRate"
        case rawDoseRate = "GRP_RawDoseRate"

        // MARK: - Introduced in V4.08
        case realTimeData = "GRP_RealTimeData"
        case rawData = "GRP_RawData"

        // MARK: - Introduced in V4.13
        case doseCounter = "GRP_DoseCounter"

        // MARK: - Deprecated in V4.13+
        case accelData = "GRP_AccelData"
        case textASCII = "GRP_TextASCII"

        // MARK: - Available in All Versions (V4.07+)
        case doseRateDB = "GRP_DoseRateDB"
        case rareData = "GRP_RareData"
        case userData = "GRP_UserData"
        case sheduleData = "GRP_SheduleData"
        case event = "GRP_Event"

        init?(rawValue: UInt8, firmwareFeatureLevel: FrameVersion) {
            if let group = GroupId.mapping[firmwareFeatureLevel]?[rawValue] {
                self = group
            } else {
                return nil
            }
        }

