content.text:
Кейс `v4_11` уже есть в enum, нужно только добавить ветку в computed property:

```swift
var firmwareFeatureLevel: FirmwareFeatureLevel {
    let targetVersion = version?.target.version
    if targetVersion?.versionCompare("4.08") == .orderedAscending {
        return .v4_07
    } else if targetVersion?.versionCompare("4.11") == .orderedAscending {
        return .v4_08
    } else if targetVersion?.versionCompare("4.13") == .orderedAscending {
        return .v4_11
    } else {
        return .v4_13
    }
}
```

Логика: `< 4.08 → v4_07`, `4.08…<4.11 → v4_08`, `4.11…<4.13 → v4_11`, `≥ 4.13 → v4_13`.

В проекте используется Swift Testing. Чтобы тестировать чисто (без `Firmware` со сложным `version: FirmwareCommand.GetVersion.Response?`), выносим маппинг в `static` на enum:

**DeviceFirmware.swift:**

```swift
var firmwareFeatureLevel: FirmwareFeatureLevel {
    .from(versionString: version?.target.version)
}
```

**Где-то рядом с enum (например в `DataBufferCommand.Model.GroupId.swift` или в новом extension):**

```swift
extension FirmwareFeatureLevel {
    static func from(versionString: String?) -> FirmwareFeatureLevel {
        let levels: [(min: String, level: FirmwareFeatureLevel)] = [
            ("4.13", .v4_13),
            ("4.11", .v4_11),
            ("4.08", .v4_08),
        ]
        return levels.first { versionString?.versionCompare($0.min) != .orderedAscending }?.level ?? .v4_07
    }
}
```

**RadiaCodeTests/FirmwareFeatureLevelTests.swift** (параметризованный тест в стиле проекта):

```swift
//
//  FirmwareFeatureLevelTests.swift
//  RadiaCodeTests
//

import Testing

@testable import Radiacode

struct FirmwareFeatureLevelTests {

    @Test(arguments: [
        (String?.none,      FirmwareFeatureLevel.v4_13),  // nil → старшая (сохраняем поведение)
        ("4.07",            .v4_07),
        ("4.08",            .v4_08),
        ("4.10",            .v4_08),                        // между 4.08 и 4.11
        ("4.11",            .v4_11),
        ("4.12",            .v4_11),                        // между 4.11 и 4.13
        ("4.13",            .v4_13),
        ("4.16",            .v4_13),                        // выше всех
    ])
    func mapping(_ version: String?, _ expected: FirmwareFeatureLevel) {
        #expect(FirmwareFeatureLevel.from(versionString: version) == expected)
    }
}
```

**Покрытие:**
- nil версия
- Граничные значения каждого диапазона (4.07, 4.08, 4.11, 4.13)
- Промежуточные (4.10 между 4.08 и 4.11; 4.12 между 4.11 и 4.13)
- Старше последней брейкпойнта (4.16)

Применять рефактор + тесты или только показал?

