private func readAlarmLevels(_ level: Alarm.Level, on device: BluetoothDevice) async -> Alarm.Level {
    let type = level.radiationType
    let multiplier = device.configurationSettings.doseAlarmMultiplier
    var updated = level
    if case .success(let response) = await device.send(command: SettingsCommand(setting: type.deviceSettingsLevel1(version: device.firmware.firmwareFeatureLevel))) {
        updated.level1 = Alarm.Level.decode(rawValue: response.value, for: type, doseAlarmMultiplier: multiplier)
    }
    if case .success(let response) = await device.send(command: SettingsCommand(setting: type.deviceSettingsLevel2(version: device.firmware.firmwareFeatureLevel))) {
        updated.level2 = Alarm.Level.decode(rawValue: response.value, for: type, doseAlarmMultiplier: multiplier)
    }
    return updated
}

