//
//  UpdateAlarmsUseCase.swift
//  RadiaCode
//
//  Created by Matvey Kozin on 19.05.2026.
//

import Foundation
import FactoryKit

extension Container {
    var updateAlarmsUseCase: Factory<UpdateAlarmsUseCase> {
        self { UpdateAlarmsUseCaseImpl() }
    }
}

protocol UpdateAlarmsUseCase {
    func update(radiationType: RadiationType, level1: Decimal?, level2: Decimal?) async
}

final class UpdateAlarmsUseCaseImpl: UpdateAlarmsUseCase {

    @Injected(\.deviceManager) private var deviceManager
    @Injected(\.deviceContainer) private var deviceContainer

    func update(radiationType: RadiationType, level1: Decimal?, level2: Decimal?) async {
        guard let device = deviceContainer.current else { return }
        let doseAlarmMultiplier = device.configurationSettings.doseAlarmMultiplier
        if let level1 {
            await write(
                setting: radiationType.deviceSettingsLevel1(version: device.firmware.firmwareFeatureLevel),
                value: Alarm.Level.encode(value: level1, for: radiationType, doseAlarmMultiplier: doseAlarmMultiplier)
            )
        }
        if let level2 {
            await write(
                setting: radiationType.deviceSettingsLevel2(version: device.firmware.firmwareFeatureLevel),
                value: Alarm.Level.encode(value: level2, for: radiationType, doseAlarmMultiplier: doseAlarmMultiplier)
            )
        }
    }

    private func write(setting: BluetoothCommandOperation, value: UInt32) async {
        await deviceManager.send(command: SettingsCommand(
            setting: setting, action: .write, payload: value
        ))
    }
}

