Все три замечания решает один паттерн — вернуть из фабрики не просто `BluetoothCommandOperation`, а пару «операция + масштаб». Тогда `version` живёт только в фабрике, encode/decode не знают про версию, никакого `where`.

**Alarm.swift** (заменить existing `extension Alarm.Level` со static encode/decode):

```swift
extension Alarm.Level {

    struct Register {
        let operation: BluetoothCommandOperation
        let scale: Scale

        enum Scale {
            case divisor(Decimal)
            case multiplier(UInt32)
        }

        func decode(_ raw: UInt32) -> Decimal {
            switch scale {
            case .divisor(let d): Decimal(raw) / d
            case .multiplier(let m): Decimal(raw) * Decimal(m)
            }
        }

        func encode(_ value: Decimal) -> UInt32 {
            switch scale {
            case .divisor(let d): UInt32(value.floatValue * d.floatValue)
            case .multiplier(let m): UInt32(value.doubleValue / Double(m) + 0.01)
            }
        }
    }
}
```

**RadiationType+BluetoothCommands.swift** (заменить целиком):

```swift
extension RadiationType {

    func registerLevel1(version: FirmwareFeatureLevel, multiplier: UInt32) -> Alarm.Level.Register {
        switch self {
        case .radiationLevel(.countRate):
            .init(operation: .countRateAlarmLevel1, scale: .divisor(10))
        case .radiationLevel(.doseRate):
            .init(operation: .doseRateAlarmLevel1, scale: .divisor(100))
        case .dose:
            if version >= .v4_11 {
                .init(operation: .doseAlarmLevel1, scale: .divisor(100))
            } else {
                .init(operation: .doseAlarmLevel1Deprecated, scale: .multiplier(multiplier))
            }
        }
    }

    func registerLevel2(version: FirmwareFeatureLevel, multiplier: UInt32) -> Alarm.Level.Register {
        switch self {
        case .radiationLevel(.countRate):
            .init(operation: .countRateAlarmLevel2, scale: .divisor(10))
        case .radiationLevel(.doseRate):
            .init(operation: .doseRateAlarmLevel2, scale: .divisor(100))
        case .dose:
            if version >= .v4_11 {
                .init(operation: .doseAlarmLevel2, scale: .divisor(100))
            } else {
                .init(operation: .doseAlarmLevel2Deprecated, scale: .multiplier(multiplier))
            }
        }
    }
}
```

**DeviceManager.swift** — `readAlarmLevels`:

```swift
private func readAlarmLevels(_ level: Alarm.Level, on device: BluetoothDevice) async -> Alarm.Level {
    let type = level.radiationType
    let multiplier = device.configurationSettings.doseAlarmMultiplier
