            Decimal(rawValue) / 100
        case .doseAlarmLevel1Deprecated, .doseAlarmLevel2Deprecated:
            // RC_VSFR_DS_LEV_100uR: val_µR = register × DS_AlarmVsfrMul
            Decimal(rawValue) * Decimal(doseAlarmMultiplier)
        default:
            0
        }
    }

    static func encode(value: Decimal, operation: BluetoothCommandOperation, doseAlarmMultiplier: UInt32) -> UInt32 {
        switch operation {
        case .countRateAlarmLevel1, .countRateAlarmLevel2:
            UInt32(value.floatValue * 10)
        case .doseRateAlarmLevel1, .doseRateAlarmLevel2:
            UInt32(value.floatValue * 100)
        case .doseAlarmLevel1, .doseAlarmLevel2:
            UInt32(value.floatValue * 100)
        case .doseAlarmLevel1Deprecated, .doseAlarmLevel2Deprecated:
            UInt32(value.doubleValue / Double(doseAlarmMultiplier) + 0.01)
        default:
            0
        }
