import Foundation

extension BluetoothCommandOperation {

    /// Декодирование сырого значения регистра в значение порога тревоги.
    func decodeAlarm(rawValue: UInt32, multiplier: UInt32) -> Decimal {
        switch self {
        case .countRateAlarmLevel1, .countRateAlarmLevel2:
            Decimal(rawValue) / 10
        case .doseRateAlarmLevel1, .doseRateAlarmLevel2:
            Decimal(rawValue) / 100
        case .doseAlarmLevel1, .doseAlarmLevel2:
            Decimal(rawValue) * Decimal(multiplier) / 100
        case .doseAlarmLevel1Deprecated, .doseAlarmLevel2Deprecated:
            Decimal(rawValue)
        default:
            0
        }
    }

    /// Кодирование значения порога тревоги в сырое значение регистра.
    func encodeAlarm(value: Decimal, multiplier: UInt32) -> UInt32 {
        switch self {
        case .countRateAlarmLevel1, .countRateAlarmLevel2:
            UInt32(value.floatValue * 10)
        case .doseRateAlarmLevel1, .doseRateAlarmLevel2:
            UInt32(value.floatValue * 100)
        case .doseAlarmLevel1, .doseAlarmLevel2:
            UInt32(value.doubleValue * 100 / Double(multiplier) + 0.01)
        case .doseAlarmLevel1Deprecated, .doseAlarmLevel2Deprecated:
            UInt32(value.doubleValue)
        default:
            0
        }
    }
}

extension RadiationType {

    /// Регистр первого порога тревоги в устройстве.
    func deviceSettingsLevel1(version: FirmwareFeatureLevel) -> BluetoothCommandOperation {
        switch self {
        case .radiationLevel(.countRate):
            return .countRateAlarmLevel1
        case .radiationLevel(.doseRate):
            return .doseRateAlarmLevel1
        case .dose:
            if version >= .v4_11 {
                return .doseAlarmLevel1
            } else {
                return .doseAlarmLevel1Deprecated
            }
        }
    }

    /// Регистр второго порога тревоги в устройстве.
    func deviceSettingsLevel2(version: FirmwareFeatureLevel) -> BluetoothCommandOperation {
        switch self {
        case .radiationLevel(.countRate):
            return .countRateAlarmLevel2
        case .radiationLevel(.doseRate):
            return .doseRateAlarmLevel2
        case .dose:
            if version >= .v4_11 {
                return .doseAlarmLevel2
            } else {
                return .doseAlarmLevel2Deprecated
            }
        }
    }
}

