content.text:
Самый чистый способ — одна функция возвращает пару `(level1, level2)`. Тогда и `if/else` ветвление, и switch — по одному разу:

**RadiationType+BluetoothCommands.swift** — заменить две функции одной:

```swift
extension RadiationType {

    /// Регистры порогов тревоги в устройстве.
    func deviceSettings(version: FirmwareFeatureLevel) -> (level1: BluetoothCommandOperation, level2: BluetoothCommandOperation) {
        switch self {
        case .radiationLevel(.countRate):
            return (.countRateAlarmLevel1, .countRateAlarmLevel2)
        case .radiationLevel(.doseRate):
            return (.doseRateAlarmLevel1, .doseRateAlarmLevel2)
        case .dose:
            if version >= .v4_11 {
                return (.doseAlarmLevel1, .doseAlarmLevel2)
            } else {
                return (.doseAlarmLevel1Deprecated, .doseAlarmLevel2Deprecated)
            }
        }
    }
}
```

**DeviceManager.swift** — `readAlarmLevels`:

```swift
private func readAlarmLevels(_ level: Alarm.Level, on device: BluetoothDevice) async -> Alarm.Level {
    let type = level.radiationType
    let multiplier = device.configurationSettings.doseAlarmMultiplier
    let version = device.firmware.firmwareFeatureLevel
    let ops = type.deviceSettings(version: version)
    var updated = level
    if case .success(let response) = await device.send(command: SettingsCommand(setting: ops.level1)) {
        updated.level1 = ops.level1.decodeAlarm(rawValue: response.value, multiplier: multiplier)
    }
    if case .success(let response) = await device.send(command: SettingsCommand(setting: ops.level2)) {
        updated.level2 = ops.level2.decodeAlarm(rawValue: response.value, multiplier: multiplier)
    }
    return updated
}
```

**UpdateAlarmsUseCase.swift** — `update`:

```swift
func update(radiationType: RadiationType, level1: Decimal?, level2: Decimal?) async {
    guard let device = deviceContainer.current else { return }
    let multiplier = device.configurationSettings.doseAlarmMultiplier
    let version = device.firmware.firmwareFeatureLevel
    let ops = radiationType.deviceSettings(version: version)
    if let level1 {
        await write(setting: ops.level1, value: ops.level1.encodeAlarm(value: level1, multiplier: multiplier))
    }
    if let level2 {
        await write(setting: ops.level2, value: ops.level2.encodeAlarm(value: level2, multiplier: multiplier))
    }
}
```

**Что получаем:**
- Одна функция вместо двух (минус ~14 строк)
- `if version >= .v4_11` один раз, switch один раз
- Семантика естественная: «дай регистры порогов для этой версии устройства» — пара всегда нужна вместе, отдельно не используется
- Callers тоже немного короче: одна строка `let ops = ...` вместо двух

Точно, write асимметричный. Тогда — одна функция с параметром индекса (`first`/`second`):

```swift
extension RadiationType {

    enum AlarmIndex { case first, second }

    func deviceSetting(_ index: AlarmIndex, version: FirmwareFeatureLevel) -> BluetoothCommandOperation {
        switch (self, index, version >= .v4_11) {
        case (.radiationLevel(.countRate), .first,  _):     .countRateAlarmLevel1
        case (.radiationLevel(.countRate), .second, _):     .countRateAlarmLevel2
        case (.radiationLevel(.doseRate),  .first,  _):     .doseRateAlarmLevel1
        case (.radiationLevel(.doseRate),  .second, _):     .doseRateAlarmLevel2
        case (.dose,                       .first,  true):  .doseAlarmLevel1
        case (.dose,                       .second, true):  .doseAlarmLevel2
        case (.dose,                       .first,  false): .doseAlarmLevel1Deprecated
        case (.dose,                       .second, false): .doseAlarmLevel2Deprecated
        }
    }
}
```

**Callers:**

```swift
// DeviceManager — читаем оба
let op1 = type.deviceSetting(.first, version: version)
let op2 = type.deviceSetting(.second, version: version)

// UpdateAlarmsUseCase — пишем только нужное
if let level1 {
    let op = radiationType.deviceSetting(.first, version: version)
    await write(setting: op, value: op.encodeAlarm(value: level1, multiplier: multiplier))
}
if let level2 {
    let op = radiationType.deviceSetting(.second, version: version)
    await write(setting: op, value: op.encodeAlarm(value: level2, multiplier: multiplier))
}
```

**Что получаем:**
- Одна функция вместо двух
- Тройное `switch (self, index, version >= .v4_11)` — никаких `if/else`, `where`, тернарников
- Каждая строка плоская и читается как таблица: `(тип, индекс, ≥v4.11?) → регистр`
- Запись остаётся асимметричной — `level1` и `level2` независимо вызываются по мере необходимости
- 8 строк раскрытия — чуть многословнее в сумме чем два switch'а, но всё на виду без условий

Ок, давай совсем минимально — ternary внутри `.dose` сжимает каждую функцию до 4 строк, structural mirror остаётся (как `==`/`!=`):

```swift
extension RadiationType {

    func deviceSettingsLevel1(version: FirmwareFeatureLevel) -> BluetoothCommandOperation {
        switch self {
        case .radiationLevel(.countRate): .countRateAlarmLevel1
        case .radiationLevel(.doseRate): .doseRateAlarmLevel1
        case .dose: version >= .v4_11 ? .doseAlarmLevel1 : .doseAlarmLevel1Deprecated
        }
    }

    func deviceSettingsLevel2(version: FirmwareFeatureLevel) -> BluetoothCommandOperation {
        switch self {
        case .radiationLevel(.countRate): .countRateAlarmLevel2
        case .radiationLevel(.doseRate): .doseRateAlarmLevel2
        case .dose: version >= .v4_11 ? .doseAlarmLevel2 : .doseAlarmLevel2Deprecated
        }
    }
}
```

Каждая функция целиком умещается в 4 строки тела, две функции — параллельные близнецы. Это в чистом виде symmetric API а не дублирование.

Или скажи в чём именно «ужасно» в предыдущем — может я неправильно понял что тебе не нравится. Варианты:
- AlarmIndex enum (новый тип) 
- `first`/`second` вместо `level1`/`level2` (call site хуже читается)
- Tuple switch с 8 кейсами (визуально многословно)
- Что-то другое

